/**
 * Template System Composable
 *
 * Provides reactive template selection and management for document rendering.
 * Active template is shared across all components via useState and persisted
 * to localStorage so the selection survives page reloads.
 */

import { onMounted, computed } from 'vue'
import type { Component } from 'vue'
import CoverLetterModern from '~/templates/modern/CoverLetterModern.vue'
import CoverLetterClassic from '~/templates/classic/CoverLetterClassic.vue'
import CoverLetterMinimal from '~/templates/minimal/CoverLetterMinimal.vue'
import CoverLetterExecutive from '~/templates/executive/CoverLetterExecutive.vue'
import CoverLetterCreative from '~/templates/creative/CoverLetterCreative.vue'
import ResignationProfessional from '~/templates/resignation-professional/ResignationProfessional.vue'
import ResignationBrief from '~/templates/resignation-brief/ResignationBrief.vue'

const LS_KEY = 'ohmydoc_template'

// Template metadata interface
export interface TemplateMetadata {
  name: string
  displayName: string
  description: string
  /** Document type names this template supports (matches DocumentTypeConfig.name) */
  documentTypes: string[]
}

// Template registry type
export interface TemplateRegistry {
  [key: string]: {
    component: Component
    metadata: TemplateMetadata
  }
}

/**
 * Template Registry
 *
 * Maps template names to their Vue components and metadata.
 * All templates use the same ParsedData props interface for consistency.
 */
const templates: TemplateRegistry = {
  modern: {
    component: CoverLetterModern,
    metadata: {
      name: 'modern',
      displayName: 'Modern',
      description: 'Professional cover letter template with modern styling and clean typography',
      documentTypes: ['cover-letter'],
    },
  },
  classic: {
    component: CoverLetterClassic,
    metadata: {
      name: 'classic',
      displayName: 'Classic',
      description: 'Traditional cover letter with table-based layout and formal styling',
      documentTypes: ['cover-letter'],
    },
  },
  minimal: {
    component: CoverLetterMinimal,
    metadata: {
      name: 'minimal',
      displayName: 'Minimal',
      description: 'Clean, minimalist cover letter design with simple structure and generous whitespace',
      documentTypes: ['cover-letter'],
    },
  },
  executive: {
    component: CoverLetterExecutive,
    metadata: {
      name: 'executive',
      displayName: 'Executive',
      description: 'Bold, confident serif template with navy accent, large name treatment, and horizontal rule dividers',
      documentTypes: ['cover-letter'],
    },
  },
  creative: {
    component: CoverLetterCreative,
    metadata: {
      name: 'creative',
      displayName: 'Creative',
      description: 'Two-column layout with vibrant accent sidebar — designed for designers, creatives, and marketers',
      documentTypes: ['cover-letter'],
    },
  },
  'resignation-professional': {
    component: ResignationProfessional,
    metadata: {
      name: 'resignation-professional',
      displayName: 'Professional',
      description: 'Formal letterhead layout with sender top-left, date top-right, and clean typography',
      documentTypes: ['resignation-letter'],
    },
  },
  'resignation-brief': {
    component: ResignationBrief,
    metadata: {
      name: 'resignation-brief',
      displayName: 'Brief',
      description: 'Compact, minimal resignation letter with just the essentials',
      documentTypes: ['resignation-letter'],
    },
  },
}

/**
 * Composable function to use the reactive template system in Vue components.
 *
 * Active template state is shared across all component instances via useState.
 * On mount, the saved localStorage value is restored (client-side only).
 *
 * @returns Reactive template state and control functions
 */
export function useTemplate() {
  // Shared reactive state — useState ensures all components see the same value
  const activeTemplate = useState<string>('activeTemplate', () => 'modern')

  // Restore from localStorage after hydration (client-only, runs once per component mount)
  onMounted(() => {
    try {
      const saved = localStorage.getItem(LS_KEY)
      if (saved && templates[saved]) {
        activeTemplate.value = saved
      }
    }
    catch {
      // Ignore storage errors (private browsing, quota exceeded, etc.)
    }
  })

  /**
   * Switch to a different template and persist the choice to localStorage.
   */
  function setActiveTemplate(name: string) {
    if (!templates[name]) {
      console.warn(`Template "${name}" not found. Available: ${Object.keys(templates).join(', ')}`)
      return
    }
    activeTemplate.value = name
    try {
      localStorage.setItem(LS_KEY, name)
    }
    catch {
      // Ignore storage errors
    }
  }

  /** Reactive component for the currently active template */
  const currentTemplate = computed<Component | undefined>(
    () => templates[activeTemplate.value]?.component,
  )

  /** Metadata for the currently active template */
  const currentTemplateMetadata = computed<TemplateMetadata | undefined>(
    () => templates[activeTemplate.value]?.metadata,
  )

  /** Names of all registered templates */
  function getAvailableTemplates(): string[] {
    return Object.keys(templates)
  }

  /** Metadata objects for all registered templates */
  function getAllTemplateMetadata(): TemplateMetadata[] {
    return Object.values(templates).map(t => t.metadata)
  }

  /** Metadata objects for templates that support the given document type */
  function getTemplatesForDocumentType(docType: string): TemplateMetadata[] {
    return Object.values(templates)
      .filter(t => t.metadata.documentTypes.includes(docType))
      .map(t => t.metadata)
  }

  return {
    activeTemplate,
    setActiveTemplate,
    currentTemplate,
    currentTemplateMetadata,
    getAvailableTemplates,
    getAllTemplateMetadata,
    getTemplatesForDocumentType,
  }
}

/**
 * Document Type Registry Composable
 *
 * Manages the registry of supported document types and the currently active
 * document type. Each document type bundles its own parser, validator,
 * available templates, and sample XML path.
 *
 * Architecture note: this composable is the single source of truth for
 * "what document type am I editing right now?" All other composables and
 * components that need type-specific behaviour should consult it.
 */

import { computed, onMounted } from 'vue'
import { parseXml as parseCoverLetterXml, validateXml as validateCoverLetterXml } from '~/composables/useXmlParser'
import type { ValidationResult, ParseResult } from '~/composables/useXmlParser'
import { parseResignationXml, validateResignationXml } from '~/composables/useResignationParser'

const LS_KEY = 'ohmydoc_document_type'

// ─── Public interfaces ────────────────────────────────────────────────────────

export interface DocumentTypeConfig {
  /** Internal key used in URLs, localStorage, and template associations */
  name: string
  /** Human-readable label shown in the UI */
  displayName: string
  /** Short description of the document type */
  description: string
  /** Path to the bundled sample XML (relative to /public) */
  sampleXmlPath: string
  /** Template to activate when this document type is first selected */
  defaultTemplate: string
  /** Names of templates registered in useTemplate that support this type */
  templates: string[]
  /** Parse an XML string into a typed data object for template rendering */
  parse: (xmlString: string) => ParseResult
  /** Validate well-formedness and schema requirements without full parsing */
  validate: (xmlString: string) => ValidationResult
}

// ─── Registry ─────────────────────────────────────────────────────────────────

/**
 * All registered document types.
 *
 * To add a new type, append an entry here following the same shape as
 * 'cover-letter'. The parser and validator functions live in their own
 * composable (e.g. useResumParser.ts) and are imported at the top of this file.
 */
const documentTypes: Record<string, DocumentTypeConfig> = {
  'cover-letter': {
    name: 'cover-letter',
    displayName: 'Cover Letter',
    description: 'Professional cover letter for job applications',
    sampleXmlPath: '/samples/cover-letter.xml',
    defaultTemplate: 'modern',
    templates: ['modern', 'classic', 'minimal'],
    parse: parseCoverLetterXml,
    validate: validateCoverLetterXml,
  },
  'resignation-letter': {
    name: 'resignation-letter',
    displayName: 'Resignation Letter',
    description: 'Formal resignation letter to notify an employer',
    sampleXmlPath: '/samples/resignation-letter.xml',
    defaultTemplate: 'resignation-professional',
    templates: ['resignation-professional', 'resignation-brief'],
    parse: parseResignationXml,
    validate: validateResignationXml,
  },
}

// ─── Composable ───────────────────────────────────────────────────────────────

/**
 * Reactive document type selection.
 *
 * State is shared across all component instances via useState and persisted
 * to localStorage so the selection survives page reloads.
 */
export function useDocumentType() {
  const activeDocumentType = useState<string>('activeDocumentType', () => 'cover-letter')

  // Restore from localStorage after hydration (client-only)
  onMounted(() => {
    try {
      const saved = localStorage.getItem(LS_KEY)
      if (saved && documentTypes[saved]) {
        activeDocumentType.value = saved
      }
    }
    catch {
      // Ignore storage errors (private browsing, quota exceeded, etc.)
    }
  })

  /**
   * Switch to a different document type and persist the choice to localStorage.
   * Also resets the active template to that type's default.
   */
  function setActiveDocumentType(name: string) {
    if (!documentTypes[name]) {
      console.warn(`Document type "${name}" not found. Available: ${Object.keys(documentTypes).join(', ')}`)
      return
    }
    activeDocumentType.value = name
    try {
      localStorage.setItem(LS_KEY, name)
    }
    catch {
      // Ignore storage errors
    }
  }

  /** Config object for the currently active document type */
  const currentDocumentType = computed<DocumentTypeConfig | undefined>(
    () => documentTypes[activeDocumentType.value],
  )

  /** All registered document type config objects */
  function getAvailableDocumentTypes(): DocumentTypeConfig[] {
    return Object.values(documentTypes)
  }

  return {
    activeDocumentType,
    currentDocumentType,
    setActiveDocumentType,
    getAvailableDocumentTypes,
  }
}

